mapper.select:
select e.*,
       c.course_name,
       u.real_name as member_name
from appreciation_comment e
         left join repertoire_info c on e.course_id = c.id
         left join sys_user u on e.member_id = u.id


        and e.schedule_id = #{scheduleId}


        and e.member_id = #{memberId}


        and e.artist_id = #{artistId}


order by e.id desc
